<script type=""text/javascript"">
    $(document).ready(function () {
        // ให้ dropdown ทุกตัวที่มี class ipSprueSystem ยิง event change ตอนโหลด
        $("".ipSprueSystem"").each(function () {
            $(this).trigger(""change"");
